def is_prime(n):
    """Check if a number is prime."""
    if n <= 1:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

def prime_length(string):
    """Return True if the length of string is a prime number, otherwise False."""
    length = len(string)
    return is_prime(length)

# Example usage:
# prime_length('Hello')     # True (length 5)
# prime_length('abcdcba')   # True (length 7)
# prime_length('kittens')    # True (length 7)
# prime_length('orange')     # False (length 6)
```
